class OrderController {
    public function store(Request $request) {
        // Validate here
        if (!$request->items) return response()->json(['error' => 'No items'], 422);
        // Business logic here
        $total = 0;
        foreach ($request->items as $item) {
            $product = Product::find($item['id']);
            if ($product->stock < $item['qty']) return response()->json(['error' => 'No stock'], 422);
            $total += $product->price * $item['qty'];
        }
        // Create order
