Code Good:
public function store(Request $request) {
    $order = Order::create($request->validated());
    ProcessOrderWebhook::dispatch($order); // Queued
    TrackEvent::dispatch('order', $order); // Queued
    $order->user->notify(new OrderConfirmation($order)); // Queued
    return response()->json($order);
    // Total: ~50ms response time
}

